import java.io.*;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        String userInput = "myData"; // User input that contains serialized data

        try {
            byte[] serializedData = userInput.getBytes(); // Simulating user input containing serialized data

            ByteArrayInputStream bis = new ByteArrayInputStream(serializedData);
            ObjectInputStream ois = new ObjectInputStream(bis);

            Object obj = ois.readObject(); // Deserializing the user input

            System.out.println("Deserialized object: " + obj.toString());
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

